+async function findConfigFile(
+  searchPath: string,
+  name: string,
+  formats: string[],
+): Promise<{ path: string; content: string } | undefined> {
+  for (const format of formats) {
+    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+    const path = resolve(join(searchPath, filename));
+    try {
+      // dnt-shim-ignore
+      const { Deno } = globalThis as any;
+      const content = Deno
+        ? await Deno.readTextFile(path)
+        : await (await import("node:fs/promises")).readFile(path, "utf8");
+      return { path, content };
+    } catch (error: unknown) {
+      if ((error as { code?: string }).code === "ENOENT" ||
+        error instanceof Deno.errors.NotFound) {
+        continue;
+      }
+      throw error;
+    }
+  }
+}
+
+function parseConfig(
+  path: string,
+  content: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : path.endsWith(".json") ? JSON.parse(content) : parseRc(content);
+    if (!isPlainObject(value)) {
+      throw new TypeError("Configuration must be a plain object.");
+    }
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator < 1) throw new TypeError("Invalid RC entry.");
+    const key = trimmed.slice(0, separator).trim();
+    let value = trimmed.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new TypeError("Unterminated quoted RC value.");
+      }
+      value = value.slice(1, -1);
+    }
+    result[key] = value === "true" ? true : value === "false" ? false :
+      value !== "" && /^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)
+      ? Number(value)
+      : value;
+  }
+  return result;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${paramCaseToCamelCase(key)}` :
+      paramCaseToCamelCase(key);
+    if (isPlainObject(item)) {
+      Object.assign(result, flattenConfig(item, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null &&
+    !Array.isArray(value) && Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function validateConfigType(key: string, value: unknown, type?: string): void {
+  const expected = type === "boolean" ? "boolean" :
+    type === "number" || type === "integer" ? "number" :
+    type === "string" || type === "file" || type === "secret" ? "string" :
+    undefined;
+  if (expected && typeof value !== expected) {
+    throw new ConfigValidationError(key, `a ${expected}`);
+  }
+  if (type === "integer" && typeof value === "number" && !Number.isInteger(value)) {
+    throw new ConfigValidationError(key, "an integer");
